import { Component, OnInit, inject } from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { HttpClient } from '@angular/common/http';

@Component({ selector: 'app-feed', template: '' })
export class FeedComponent implements OnInit {
  private http = inject(HttpClient);
  private destroyRef = inject(DestroyRef); // auto from DI
  private clickHandler = () => console.log('clicked');

  ngOnInit() {
    // Subscription auto-cancelled when component destroys
    this.http.get('/api/feed')
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe(data => console.log(data));

    window.addEventListener('click', this.clickHandler);
  }

  ngOnDestroy() {
    window.removeEventListener('click', this.clickHandler);
  }
}

@Injectable({ providedIn: 'root' })
export class WsService {
  private socket$ = webSocket<Message>('wss://api.example.com/ws');
  private messages$ = new BehaviorSubject<Message[]>([]);

  readonly stream$ = this.socket$.pipe(
    retry({ delay: (_, count) => timer(Math.min(1000 * 2 ** count, 30000)) })
  );

  send(payload: Message): void {
    // Optimistic update
    this.messages$.next([...this.messages$.value, payload]);
    this.socket$.next(payload);
  }

  getMessages(): Observable<Message[]> {
    return this.messages$.asObservable();
  }
}

