const EnvSchema = z.object({
  apiUrl: z.string().url(),
  authDomain: z.string().min(1),
  production: z.boolean(),
});

export type AppEnv = z.infer<typeof EnvSchema>;
export const APP_ENV = new InjectionToken<AppEnv>('APP_ENV');

